    return None

def norm(s):
    return normalize(s)
def lcs_length(a, b):
    # compute length of LCS on characters
    m, n = len(a), len(b)
    dp = [0]*(n+1)
    for i in range(1, m+1):
        prev = 0
        for j in range(1, n+1):
            tmp = dp[j]
            if a[i-1]==b[j-1]:
                dp[j] = prev + 1
            else:
                dp[j] = max(dp[j], dp[j-1])
            prev = tmp
    return dp[n]

def sim(a,b):
    a2, b2 = norm(a), norm(b)
    # LCS normalized by max length
    l = lcs_length(a2, b2)
    return l/max(len(a2), len(b2))

