def token_f1(a,b):
    # tokenization by spaces after normalization
    a_toks = norm(a).split()
    b_toks = norm(b).split()
    a_set = set(a_toks); b_set = set(b_toks)
    inter = a_set.intersection(b_set)
    if not a_set or not b_set:
        return 0.0
    prec = len(inter)/len(a_set)
    rec = len(inter)/len(b_set)
    if prec+rec==0:
        return 0.0
    return 2*prec*rec/(prec+rec)

